<template>


	<view class="wrap">

		<!-- <u-navbar :custom-back="backpage">
			<u-search v-model="keyword" placeholder="请输入订单号" height="56" @search="search" @custom="search">
			</u-search>

		</u-navbar>

 -->
		<scroll-view scroll-y style="height: 100%;width: 100%;background-color: #f5f7fa;" @scrolltolower="reachBottom">
			<view class="page-box">
				<view class="order" v-for="(order, orderindex) in list" :key="order.id">
					<!-- <view class="top"> -->
					<!-- <view class="left"> -->

					<!-- <view class="store">{{order._create_time}}</view> -->
					<!-- <u-icon name="zhuanfa" :size="30" color="rgb(94,94,94)"></u-icon> -->
					<!-- <u-icon name="arrow-right" color="rgb(203,203,203)" :size="26"></u-icon> -->
					<!-- </view> -->
					<!-- <view class="right" :style="{
									color:statusColor[order.goods_type].color
								}">{{ order._goods_type_text }}</view> -->
					<!-- </view> -->

					<view class="item" @click="$util.on(`/pages/goods/detail?id=${order.id}`)">
						<view class="good-type" :style="{
							backgroundColor: 	item.is_goods_type?'#12bd4380':item.goods_type==1?'#ff450080':'#07b4ff80',
						}">
							{{item.is_goods_type?'人工代充':item.goods_type==1?'卡密兑换':'自动发货'}}
						</view>
						<view class="left">
							<image :src="order.goods_img" mode="aspectFill"></image>
						</view>
						<view class="content">
							<view class="title u-line-2">{{ order.goods_name }}</view>

							<view class="price" style="color: #909399;">
								￥{{ priceInt(order.goods_price) }}
								<text class="decimal">.{{ priceDecimal(order.goods_price) }}</text>
							</view>
							<view class="bottom">

								<view class="store" style="color: #909399;">{{order.create_time}}</view>
								<view class="evaluate btn"
									style="color: #000;border-color: #545454;border:2rpx solid #ccc;">购买
								</view>

							</view>
						</view>
						<view class="del" @click.stop="showDel(order)" style="position: absolute;right: 20rpx;">
							<u-icon name="trash" color="#ccc" size="40"></u-icon>
						</view>

					</view>



				</view>


				<u-loadmore :status="loadStatus" icon-type="circle" v-if="list.length >0 && loaded" />
			</view>
			<u-empty v-if="loaded &&  list.length == 0"></u-empty>


		</scroll-view>

		<u-modal v-model="show" :content="'确定删除'+item.goods_name" title="删除收藏商品" @confirm="delfavorite"
			:show-cancel-button="true"></u-modal>
	</view>



</template>

<script>
	export default {
		data() {
			return {
				show: false,
				item: {
					id: 0,
					goods_name: '',
				},
				keyword: '',
				sys: this.$util.sys(),
				limit: 10,


				loadStatus: 'loadmore',
				page: 1,

				count: 0,
				list: [],
				loaded: false,
				statusColor: [{
						color: '#999'
					},


					{
						color: '#90dd90'
					},

					{
						color: '#f00'
					}
				],

				current: 0,
				swiperCurrent: 0,

				dx: 0,
			};
		},
		onLoad(e) {


			if (e.status) {
				this.swiperCurrent = e.status
				this.current = e.status

			}

			this.loadData(this.swiperCurrent);
		},
		computed: {
			// 价格小数
			priceDecimal() {
				return val => {
					if (val !== parseInt(val)) return val.split('.')[1];
					else return '00';
				};
			},
			// 价格整数
			priceInt() {
				return val => {
					if (val !== parseInt(val)) return val.split('.')[0];
					else return val;
				};
			}
		},
		methods: {
			showDel(item) {
				this.item = item
				this.show = true
			},
			delfavorite() {

				this.$u.api.delfavorite({

						ids: [this.item.id]
					})
					.then(res => {

						this.$util.msg('删除成功')

						this.search()
					}).catch(res => {})


			},
			backpage() {
				this.$util.back()
			},
			paste(val) {

				uni.setClipboardData({
					data: val,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			reachBottom() {


				setTimeout(() => {
					this.loadData(this.current);
				}, 200);

			},
			search() {
				this.list = []
				this.page = 1
				this.loaded = false
				this.current = 0
				this.swiperCurrent = 0
				this.loadData(0);

			},
			// 页面数据
			async loadData(idx) {

				uni.showLoading({
					mask: true,
					title: '加载中...',

				})
				await this.$u.api.favorite({

						keyword: this.keyword,
						page: this.page,
						limit: this.limit,
					})
					.then(res => {
						if (res.list.length == 0) {
							this.loadStatus = 'nomore'
						} else {
							if (this.list.length > 0) {
								this.list = this.list.concat(res.list)

							} else {
								this.list = res.list

							}

							if (res.list.length < this.limit) {
								this.loadStatus = 'nomore'
							} else {
								this.loadStatus = 'loadmore'
							}


							this.page++
						}
					}).catch(res => {})

				this.loaded = true;
				//loaded新字段用于表示数据加载完毕，如果为空可以显示空白页
				uni.hideLoading()
				// console.log(item	);
			},
			// 总价
			totalPrice(item) {
				let price = 0;
				item.map(val => {
					price += parseFloat(val.price);
				});
				return price.toFixed(2);
			},
			// 总件数
			totalNum(item) {
				let num = 0;
				item.map(val => {
					num += val.number;
				});
				return num;
			},
			// tab栏切换
			change(index) {
				this.swiperCurrent = index;
				this.loadData(index);
			},
			transition({
				detail: {
					dx
				}
			}) {

				this.$refs.tabs.setDx(dx);
			},
			animationfinish({
				detail: {
					current
				}
			}) {

				this.$refs.tabs.setFinishCurrent(current);
				this.swiperCurrent = current;
				this.current = current;
				if (!this.orderList[current].loaded) {
					this.loadData(current)
				}
			},
		}
	};
</script>

<style scoped>
	/* #ifndef H5 */
	page {
		height: 100%;
		background-color: #f2f2f2;
	}

	/* #endif */
</style>

<style lang="scss" scoped scoped>
	.order {
		width: 710rpx;
		background-color: #ffffff;
		margin: 20rpx auto;
		border-radius: 20rpx;
		box-sizing: border-box;
		padding: 20rpx;
		font-size: 28rpx;

		.top {
			display: flex;
			justify-content: space-between;

			.left {
				display: flex;
				align-items: center;

				.store {
					margin: 0 10rpx;
					font-size: 24rpx;
					font-weight: bold;
				}
			}

			.right {
				color: $u-type-warning-dark;
			}
		}

		.item {
			position: relative;
			display: flex;
			// margin: 20rpx 0 0;
			justify-content: flex-start;

			.left {
				margin-right: 20rpx;

				image {
					width: 160rpx;
					height: 160rpx;
					border-radius: 10rpx;
				}
			}

			.content {

				.title {
					font-size: 28rpx;
					width: 440rpx;
					// line-height: 50rpx;
				}

				.type {
					// margin: 10rpx 0;
					// font-size: 24rpx;
					color: $u-tips-color;
				}

				.delivery-time {
					// color: #e5d001;
					font-size: 24rpx;
				}

				.content-box {
					display: flex;
					gap: 20rpx;
				}
			}

			.right {
				margin-left: 10rpx;
				padding-top: 8rpx;
				text-align: right;

				.decimal {
					font-size: 24rpx;
					margin-top: 4rpx;
				}

				.number {
					color: $u-tips-color;
					font-size: 24rpx;
				}
			}
		}

		.total {
			// margin-top: 20rpx;
			text-align: right;
			font-size: 24rpx;

			.total-price {
				font-size: 32rpx;
			}

			.decimal {
				font-size: 24rpx;
				margin-top: 4rpx;
			}
		}

		.bottom {
			display: flex;
			// margin-top: 20rpx;
			// padding: 0 10rpx;
			// gap: 20rpx;
			justify-content: space-between;
			align-items: center;
			width: 480rpx;

			.btn {
				line-height: 52rpx;
				width: 160rpx;
				border-radius: 24rpx;
				border: 2rpx solid $u-border-color;
				font-size: 24rpx;
				text-align: center;
				color: $u-type-info-dark;
			}

			.evaluate {
				color: $u-type-warning-dark;
				border-color: $u-type-warning-dark;
			}
		}
	}

	.centre {
		text-align: center;
		margin: 200rpx auto;
		font-size: 32rpx;

		image {
			width: 164rpx;
			height: 164rpx;
			border-radius: 50%;
			margin-bottom: 20rpx;
		}

		.tips {
			font-size: 24rpx;
			color: #999999;
			margin-top: 20rpx;
		}

		.btn {
			margin: 80rpx auto;
			width: 200rpx;
			border-radius: 32rpx;
			line-height: 64rpx;
			color: #ffffff;
			font-size: 26rpx;
			background: linear-gradient(270deg, rgba(249, 116, 90, 1) 0%, rgba(255, 158, 1, 1) 100%);
		}
	}

	.wrap {
		display: flex;
		flex-direction: column;
		height: calc(100vh - var(--window-top));
		width: 100%;
	}

	.swiper-box {
		flex: 1;
		background-color: #f4f5f8;
	}

	.swiper-item {
		height: 100%;
	}

	.good-type {
		position: absolute;
		top: 0;
		left: 0;
		padding: 0 4rpx;
		z-index: 2;
		line-height: 32rpx;
		font-size: 22rpx;
		color: #fff;
		border-radius: 6rpx;
	}
</style>